def seed():
    os.makedirs(os.path.dirname(DB_PATH), exist_ok=True)
    conn = sqlite3.connect(DB_PATH)
    c = conn.cursor()
    c.execute('DROP TABLE IF EXISTS schemes')
    c.execute('''CREATE TABLE schemes (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL,
        category TEXT NOT NULL,
        ministry TEXT,
        description TEXT,
        min_age INTEGER,
        max_age INTEGER,
        max_income INTEGER,
        gender_required TEXT DEFAULT 'All',
        caste_required TEXT DEFAULT 'All',
        bpl_required BOOLEAN DEFAULT 0,
        official_link TEXT,
        benefits TEXT,
        documents TEXT
    )''')
    c.executemany('''INSERT INTO schemes
        (name,category,ministry,description,min_age,max_age,max_income,
         gender_required,caste_required,bpl_required,official_link,benefits,documents)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)''', SCHEMES)
    conn.commit()
    conn.close()
    print(f"Seeded {len(SCHEMES)} schemes into database")

if __name__ == '__main__':
    seed()
